(function () {
  var nodes = [{ v: 1, x: 150, y: 190 }, { v: 2, x: 90, y: 125 }, { v: 3, x: 210, y: 125 }, { v: 4, x: 60, y: 60 }, { v: 6, x: 180, y: 60 }, { v: 12, x: 120, y: 10 }], edges = [[1, 2], [1, 3], [2, 4], [2, 6], [3, 6], [4, 12], [6, 12]];
  function style() { if (document.getElementById('hd-style')) return; var s = document.createElement('style'); s.id = 'hd-style'; s.textContent = '.hd-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.hd-board{position:relative;width:300px;height:250px;margin:10px auto;background:#f8f9fa;border-radius:12px}.hd-board svg{position:absolute;inset:0;width:100%;height:100%}.hd-node{position:absolute;width:42px;height:42px;margin:-21px 0 0 -21px;border-radius:50%;border:2px solid #007bff;background:#e8f4fd;color:#174ea6;display:flex;align-items:center;justify-content:center;font-weight:700;cursor:pointer;z-index:2}.hd-up{background:#d4edda;border-color:#28a745;color:#166534}.hd-low{background:#fff3cd;border-color:#ffc107;color:#7a4b00}.hd-selected{box-shadow:0 0 0 5px rgba(0,123,255,.22)}.hd-out{padding:10px;border-radius:8px;background:#f8f9fa;border-left:4px solid #007bff}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.hdMounted) return; host.dataset.hdMounted = '1'; style(); var html = '<div class="hd-wrap"><h4>Sơ đồ Hasse: chia hết trên {1,2,3,4,6,12}</h4><div class="hd-board"><svg>'; edges.forEach(function (e) { var a = nodes.find(function (n) { return n.v === e[0]; }), b = nodes.find(function (n) { return n.v === e[1]; }); html += '<line x1="' + a.x + '" y1="' + a.y + '" x2="' + b.x + '" y2="' + b.y + '" stroke="#6c757d" stroke-width="2"></line>'; }); html += '</svg>' + nodes.map(function (n) { return '<button type="button" class="hd-node" style="left:' + n.x + 'px;top:' + n.y + 'px" data-v="' + n.v + '">' + n.v + '</button>'; }).join('') + '</div><div class="hd-out">Bấm một nút để tô cận dưới và cận trên.</div></div>'; host.innerHTML = html; var out = host.querySelector('.hd-out'); host.addEventListener('click', function (e) { var v = Number(e.target.getAttribute('data-v')); if (!v) return; Array.prototype.forEach.call(host.querySelectorAll('.hd-node'), function (n) { var x = Number(n.dataset.v); n.classList.toggle('hd-selected', x === v); n.classList.toggle('hd-low', v % x === 0 && x !== v); n.classList.toggle('hd-up', x % v === 0 && x !== v); }); out.innerHTML = 'Đang chọn <strong>' + v + '</strong>. Cận dưới: ' + nodes.filter(function (n) { return v % n.v === 0; }).map(function (n) { return n.v; }).join(', ') + '. Cận trên: ' + nodes.filter(function (n) { return n.v % v === 0; }).map(function (n) { return n.v; }).join(', ') + '.'; }); }
  function safeMount(host) { try { mount(host); } catch (err) { if (host) host.innerHTML = '<div class="hd-out">Không thể tải demo sơ đồ Hasse. Hãy tải lại trang.</div>'; } }
  document.addEventListener('DOMContentLoaded', function () { Array.prototype.forEach.call(document.querySelectorAll('[data-demo="hasse-diagram"]'), safeMount); });
})();
